import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { 
  ProjectState, 
  WidgetType, 
  AIResponse, 
  ThinkingBudgetLevel, 
  ProjectNode,
  GroundingSource,
  DataStore,
  ProcessingStage,
  ChatMessage
} from "../types";
import { validateAndSanitizeWidget } from "./sanitizer";
import { 
    getDataSystemInstruction, 
    constructDataPrompt, 
    dataAgentSchema,
    getUISystemInstruction,
    constructUIPrompt,
    uiAgentSchema
} from "./prompts";

// Helper to parse loose JSON
const safeParse = (jsonText: string) => {
    let parsed;
    try {
        parsed = JSON.parse(jsonText);
    } catch (e) {
        // Try to find the JSON block
        const match = jsonText.match(/\{[\s\S]*\}/);
        if (match) {
            try { parsed = JSON.parse(match[0]); } catch(e2) {}
        }
    }

    if (!parsed) throw new Error("Response was not valid JSON");

    // UNWRAP LOGIC: Fix for models that output the schema definition populated with data
    // Pattern: { type: "OBJECT", properties: { ...data... } }
    if (parsed.properties && !parsed.thoughtProcess) {
        // Check if properties contains the fields we expect 
        // We use 'thoughtProcess' as the canary since it's in both Data and UI schemas
        if (parsed.properties.thoughtProcess) {
            return parsed.properties;
        }
    }

    return parsed;
};

// Helper to wrap promise with cancellation
const wrapWithAbort = <T>(promise: Promise<T>, signal?: AbortSignal): Promise<T> => {
    if (!signal) return promise;
    return Promise.race([
        promise,
        new Promise<T>((_, reject) => {
            const abortHandler = () => reject(new Error("Request cancelled by user."));
            if (signal.aborted) {
                abortHandler();
            } else {
                signal.addEventListener('abort', abortHandler);
            }
        })
    ]);
};

// Helper for Custom API Calls (OpenAI Compatible)
const callCustomAI = async (
    endpoint: string,
    modelName: string,
    apiKey: string | undefined,
    systemInstruction: string,
    history: ProjectNode[],
    promptParts: any[], // From constructDataPrompt/constructUIPrompt
    schema: any,
    signal?: AbortSignal
): Promise<any> => {

    // Convert history + current prompt parts to standard OpenAI messages
    const messages: { role: string; content: string }[] = [];

    // 1. System Message (with Schema Injection)
    const schemaString = JSON.stringify(schema, null, 2);
    const fullSystemInstruction = `${systemInstruction}\n\nIMPORTANT: You must output strictly valid JSON matching this schema:\n${schemaString}\n\nDo not include markdown formatting like \`\`\`json in your response. Just the raw JSON.`;
    messages.push({ role: 'system', content: fullSystemInstruction });

    // 2. Add Prompt Content
    // Note: promptParts from constructDataPrompt usually contains: 
    // - A massive context string (history + current request)
    // - Attachment placeholders
    // We will concatenate all text parts.
    // For custom models, we are currently ignoring images to ensure compatibility with text-only models like Mistral-7B.
    let userContent = "";
    promptParts.forEach(p => {
        if (p.text) userContent += p.text + "\n";
        // Inline data (images) skipped for custom provider text-only compatibility
    });

    messages.push({ role: 'user', content: userContent });

    const headers: Record<string, string> = {
        'Content-Type': 'application/json'
    };
    if (apiKey) {
        headers['Authorization'] = `Bearer ${apiKey}`;
    }

    const body = {
        model: modelName,
        messages: messages,
        temperature: 0.7,
        max_tokens: 4000, // Sufficient for large JSON
        response_format: { type: "json_object" }
    };

    const response = await fetch(endpoint, {
        method: 'POST',
        headers,
        body: JSON.stringify(body),
        signal
    });

    if (!response.ok) {
        const errText = await response.text();
        throw new Error(`Custom API Error (${response.status}): ${errText}`);
    }

    const json = await response.json();
    const content = json.choices?.[0]?.message?.content;

    if (!content) throw new Error("Custom API returned empty content");

    return safeParse(content);
};

export const generateNodeResponse = async (
  targetNodeId: string,
  projectState: ProjectState,
  mode: 'branch' | 'chat' | 'synthesize' | 'refresh' | 'cleanup',
  modelName: string, // Used for Gemini
  thinkingBudget: ThinkingBudgetLevel,
  isGroundingEnabled: boolean,
  onProgress?: (stage: ProcessingStage) => void,
  signal?: AbortSignal
): Promise<AIResponse> => {
  const node = projectState.nodes[targetNodeId];
  if (!node) throw new Error("Node not found");

  const checkAbort = () => {
    if (signal?.aborted) throw new Error("Request cancelled by user.");
  };

  checkAbort();

  // --- PREPARE HISTORY ---
  const history: ProjectNode[] = [];
  let curr: ProjectNode | undefined = node;
  while (curr) {
    history.unshift(curr);
    curr = curr.parentId ? projectState.nodes[curr.parentId] : undefined;
  }

  // --- DETERMINE BASELINE STATE ---
  let lastKnownKnowledge = {};
  let lastKnownData: { stores: DataStore[] } = { stores: [] };

  history.forEach((n) => {
    if (n.data?.projectKnowledge && Object.keys(n.data.projectKnowledge).length > 0) {
        lastKnownKnowledge = n.data.projectKnowledge;
    }
    if (n.data?.projectData) {
        lastKnownData = n.data.projectData;
    }
  });

  // Current node context overrides
  if (node.data?.projectKnowledge && Object.keys(node.data.projectKnowledge).length > 0) {
      lastKnownKnowledge = node.data.projectKnowledge;
  }
  if (node.data?.projectData) {
      lastKnownData = node.data.projectData;
  }

  // ==========================================
  // PHASE 1: DATA ARCHITECT
  // ==========================================
  onProgress?.('analyzing');
  checkAbort();

  const dataPrompt = constructDataPrompt(history, node, lastKnownKnowledge, lastKnownData, mode);
  let dataResult: any;
  let groundingSources: GroundingSource[] = [];

  if (projectState.modelProvider === 'gemini') {
      const budgetMap: Record<ThinkingBudgetLevel, number> = { low: 512, medium: 4096, high: 32768 };
      const isMapsModel = modelName.includes("2.5");
      const tools: any[] = [];
      if (isGroundingEnabled) {
          tools.push({ googleSearch: {} });
          if (isMapsModel) tools.push({ googleMaps: {} });
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const dataConfig: any = {
          systemInstruction: getDataSystemInstruction(isGroundingEnabled),
          tools: tools,
          thinkingConfig: { thinkingBudget: budgetMap[thinkingBudget] },
          responseMimeType: "application/json",
          responseSchema: dataAgentSchema
      };

      const dataResponse = await wrapWithAbort(ai.models.generateContent({
          model: modelName,
          contents: { parts: dataPrompt },
          config: dataConfig
      }), signal) as GenerateContentResponse;

      checkAbort();
      dataResult = safeParse(dataResponse.text || "{}");

      // Extract Grounding
      const groundingChunks = dataResponse.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (groundingChunks) {
          groundingChunks.forEach((chunk: any) => {
              if (chunk.web?.uri && chunk.web?.title) groundingSources.push({ title: chunk.web.title, uri: chunk.web.uri });
              if (chunk.maps?.uri && chunk.maps?.title) groundingSources.push({ title: `📍 ${chunk.maps.title}`, uri: chunk.maps.uri });
          });
      }
  } else {
      // CUSTOM PROVIDER
      const { endpoint, modelName: customModel, apiKey } = projectState.customModelConfig;
      if (!endpoint || !customModel) throw new Error("Missing Custom API Configuration");

      dataResult = await callCustomAI(
          endpoint,
          customModel,
          apiKey,
          getDataSystemInstruction(false), // Grounding disabled for custom
          history,
          dataPrompt,
          dataAgentSchema,
          signal
      );
  }

  // ==========================================
  // PHASE 1.5: APPLY DATA UPDATES (IN-MEMORY)
  // ==========================================
  onProgress?.('updating_data');
  checkAbort();

  if (!dataResult.updatedData) dataResult.updatedData = { summary: "No summary", keyPoints: [] };

  // Parse nested JSON strings if present
  if (dataResult.updatedData.projectKnowledgeJson) {
      try { dataResult.updatedData.projectKnowledge = JSON.parse(dataResult.updatedData.projectKnowledgeJson); } catch(e) {}
  } else {
      dataResult.updatedData.projectKnowledge = lastKnownKnowledge;
  }

  // Execute Store Operations
  let updatedStores = lastKnownData.stores ? [...lastKnownData.stores] : [];
  if (dataResult.updatedData.projectDataUpdates && Array.isArray(dataResult.updatedData.projectDataUpdates)) {
      dataResult.updatedData.projectDataUpdates.forEach((op: any) => {
          const existingIdx = updatedStores.findIndex(s => s.id === op.storeId);
          let schemaMap = {};
          if (op.schemaJson) try { schemaMap = JSON.parse(op.schemaJson); } catch(e) {}
          let recordsArr = [];
          if (op.recordsJson) try { recordsArr = JSON.parse(op.recordsJson); } catch(e) {}

          if (op.operation === 'DELETE_STORE') {
              if (existingIdx !== -1) updatedStores.splice(existingIdx, 1);
          } 
          else if (op.operation === 'CREATE_OR_UPDATE_STORE') {
              if (existingIdx !== -1) {
                  updatedStores[existingIdx] = {
                      ...updatedStores[existingIdx],
                      name: op.name || updatedStores[existingIdx].name,
                      schema: (Object.keys(schemaMap).length > 0) ? schemaMap : updatedStores[existingIdx].schema,
                  };
              } else {
                  updatedStores.push({
                      id: op.storeId,
                      name: op.name || op.storeId,
                      schema: schemaMap,
                      records: []
                  });
              }
          } 
          else if (op.operation === 'UPSERT_RECORDS') {
              if (existingIdx !== -1) {
                  const store = updatedStores[existingIdx];
                  const mergedRecords = [...store.records];

                  // SMART DE-DUPLICATION LOGIC
                  const commonKeyFields = ['name', 'title', 'label', 'content', 'task', 'feature', 'ticket', 'item'];
                  const schemaKeys = Object.keys(store.schema || {});
                  const businessKey = commonKeyFields.find(k => schemaKeys.includes(k) || (store.records.length > 0 && k in store.records[0]));

                  recordsArr.forEach((newRec: any) => {
                      let recordId = newRec.id;

                      if (!recordId && businessKey && newRec[businessKey]) {
                          const candidates = mergedRecords.filter(r => r[businessKey] === newRec[businessKey]);
                          if (candidates.length === 1) {
                              recordId = candidates[0].id;
                          }
                      }

                      if (!recordId) {
                           recordId = `gen-${Math.random().toString(36).substr(2, 9)}`;
                           newRec.id = recordId;
                      } else {
                          newRec.id = recordId;
                      }

                      const matchIdx = mergedRecords.findIndex(r => r.id === recordId);
                      if (matchIdx !== -1) {
                          mergedRecords[matchIdx] = { ...mergedRecords[matchIdx], ...newRec };
                      } else {
                          mergedRecords.push(newRec);
                      }
                  });
                  updatedStores[existingIdx] = { ...store, records: mergedRecords };
              } else {
                  recordsArr.forEach((r:any) => { if (!r.id) r.id = `gen-${Math.random().toString(36).substr(2, 9)}`; });
                  updatedStores.push({
                      id: op.storeId,
                      name: op.name || op.storeId,
                      schema: schemaMap,
                      records: recordsArr
                  });
              }
          }
          else if (op.operation === 'DELETE_RECORDS') {
              if (existingIdx !== -1) {
                  const store = updatedStores[existingIdx];
                  const idsToDelete = op.recordIds || [];
                  const filteredRecords = store.records.filter(r => !idsToDelete.includes(r.id));
                  updatedStores[existingIdx] = { ...store, records: filteredRecords };
              }
          }
      });
  }

  const nextDataState = {
      stores: updatedStores
  };

  dataResult.updatedData.projectData = nextDataState;

  // ==========================================
  // PHASE 2: UI DESIGNER
  // ==========================================
  onProgress?.('designing_ui');
  checkAbort();

  const uiPrompt = constructUIPrompt(node.userInput, nextDataState, dataResult.thoughtProcess);
  let uiResult;

  try {
      if (projectState.modelProvider === 'gemini') {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const uiConfig: any = {
              systemInstruction: getUISystemInstruction(),
              thinkingConfig: { thinkingBudget: 1024 }, 
              responseMimeType: "application/json",
              responseSchema: uiAgentSchema
          };

          const uiResponse = await wrapWithAbort(ai.models.generateContent({
              model: modelName, 
              contents: { parts: uiPrompt },
              config: uiConfig
          }), signal) as GenerateContentResponse;
          uiResult = safeParse(uiResponse.text || "{}");
      } else {
          // CUSTOM PROVIDER
          const { endpoint, modelName: customModel, apiKey } = projectState.customModelConfig;
          uiResult = await callCustomAI(
              endpoint,
              customModel,
              apiKey,
              getUISystemInstruction(),
              [], // UI Agent doesn't need history, just the prompt constructed from Data Agent output
              uiPrompt,
              uiAgentSchema,
              signal
          );
      }
  } catch (err: any) {
      if (err.message === "Request cancelled by user.") throw err;
      console.error("UI Agent Failed", err);
      uiResult = { updatedVisualization: { title: "Data Only", widgets: [] } };
  }

  // ==========================================
  // MERGE & SANITIZE
  // ==========================================
  onProgress?.('rendering');
  checkAbort();

  if (!uiResult.updatedVisualization) uiResult.updatedVisualization = { title: "Visualization Error", widgets: [] };

  if (groundingSources.length > 0) {
      const hasRefs = uiResult.updatedVisualization.widgets?.some((w: any) => w.type === WidgetType.REFERENCES);
      if (!hasRefs) {
          if (!uiResult.updatedVisualization.widgets) uiResult.updatedVisualization.widgets = [];
          uiResult.updatedVisualization.widgets.push({
              type: WidgetType.REFERENCES,
              title: "Research & Locations",
              contentItems: groundingSources
          });
      }
  }

  if (uiResult.updatedVisualization.widgets) {
      uiResult.updatedVisualization.widgets = uiResult.updatedVisualization.widgets.map(validateAndSanitizeWidget);
  }

  return {
      updatedData: dataResult.updatedData,
      updatedVisualization: uiResult.updatedVisualization,
      chatReply: dataResult.chatReply || "Processing complete.",
      thoughtProcess: `${dataResult.thoughtProcess}\n\n[UI Designer]: ${uiResult.thoughtProcess || 'Generated widgets based on data.'}`,
      groundingSources: groundingSources.length > 0 ? groundingSources : undefined,
      consolidatedUserIntent: dataResult.consolidatedUserIntent,
      debugInfo: {
          timestamp: Date.now(),
          request: {
              model: projectState.modelProvider === 'gemini' ? modelName : projectState.customModelConfig.modelName,
              prompt: "Multi-step agent chain execution",
              budget: projectState.thinkingBudget === 'low' ? 512 : projectState.thinkingBudget === 'medium' ? 4096 : 32768,
              grounding: isGroundingEnabled
          },
          response: `DATA AGENT:\n${JSON.stringify(dataResult, null, 2)}\n\nUI AGENT:\n${JSON.stringify(uiResult, null, 2)}`
      }
  };
};

import React, { useMemo } from 'react';
import { WidgetData, WidgetType, MindmapNode, DataStore } from '../../types';
import { GanttWidget } from './GanttWidget';
import { ChartWidget } from './ChartWidget';
import { KanbanWidget } from './KanbanWidget';
import { MindmapWidget } from './MindmapWidget';
import { MapWidget } from './MapWidget';
import { MetricsWidget } from './MetricsWidget';
import { RiskMatrixWidget } from './RiskMatrixWidget';
import { ReferencesWidget } from './ReferencesWidget';
import { ErrorWidget } from './ErrorWidget';
import { CodeWidget } from './CodeWidget';
import { TableWidget } from './TableWidget';

interface WidgetRendererProps {
  widget: WidgetData;
  onMindmapNodeClick?: (node: MindmapNode) => void;
  isExpanded?: boolean;
  projectData?: { stores: DataStore[] }; // Pass the full project data context
}

// --- HYDRATION HELPERS ---

const hydrateWidget = (widget: WidgetData, stores: DataStore[]): any => {
    // If no data source or invalid data source, return widget as is (Legacy mode)
    if (!widget.dataSource || !widget.dataSource.storeId) return widget;

    const store = stores.find(s => s.id === widget.dataSource!.storeId);
    if (!store) {
        console.warn(`Widget ${widget.title} referenced missing store: ${widget.dataSource!.storeId}`);
        return widget;
    }

    // Convert array-based mapping to Record<widgetKey, storeColumn>
    const mappingArray = widget.dataSource!.fieldMapping || [];
    const mapping: Record<string, string> = {};
    if (Array.isArray(mappingArray)) {
        mappingArray.forEach(m => {
            if (m.widgetKey && m.storeColumn) {
                mapping[m.widgetKey] = m.storeColumn;
            }
        });
    } else {
        // Fallback for single object or legacy map
        const asObj = mappingArray as any;
        if (asObj.widgetKey && asObj.storeColumn) {
             mapping[asObj.widgetKey] = asObj.storeColumn;
        } else {
             Object.assign(mapping, mappingArray);
        }
    }

    const records = store.records || [];

    // Helper to map a record using the field mapping
    const mapRecord = (record: any) => {
        const result: any = { ...record }; // Keep original fields for flexibility
        Object.entries(mapping).forEach(([widgetKey, storeColumn]) => {
            if (storeColumn && record[storeColumn] !== undefined) {
                result[widgetKey] = record[storeColumn];
            }
        });
        return result;
    };

    switch (widget.type) {
        case WidgetType.GANTT:
            return {
                ...widget,
                tasks: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        id: mapped.id || r.id || String(Math.random()),
                        name: mapped.name || "Untitled Task",
                        start: mapped.start,
                        end: mapped.end,
                        progress: mapped.progress ? Number(mapped.progress) : 0,
                        owner: mapped.owner,
                        status: mapped.status,
                        isEstimated: mapped.isEstimated,
                        dependencies: mapped.dependencies
                    };
                })
            };

        case WidgetType.METRICS:
            return {
                ...widget,
                contentItems: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        label: mapped.label || "Metric",
                        value: mapped.value,
                        trend: mapped.trend,
                        status: mapped.status,
                        description: mapped.description
                    };
                })
            };

        case WidgetType.REFERENCES:
            return {
                ...widget,
                contentItems: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        title: mapped.title || "Reference",
                        uri: mapped.uri || "#",
                    };
                })
            };

        case WidgetType.RISK_MATRIX:
            return {
                ...widget,
                risks: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        id: mapped.id || r.id,
                        label: mapped.label || "Risk",
                        impact: Number(mapped.impact),
                        likelihood: Number(mapped.likelihood),
                        mitigation: mapped.mitigation
                    };
                })
            };

        case WidgetType.MAP:
            return {
                ...widget,
                markers: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        id: mapped.id || r.id,
                        label: mapped.label || "Location",
                        address: mapped.address,
                        latitude: Number(mapped.latitude),
                        longitude: Number(mapped.longitude),
                        description: mapped.description,
                        type: mapped.type
                    };
                })
            };

        case WidgetType.TABLE:
            // For tables, if mapping exists, we use it to construct the view
            const hasMapping = Object.keys(mapping).length > 0;
            // If mapping exists, the headers are the widgetKeys. Otherwise use store schema.
            const headers = hasMapping ? Object.keys(mapping) : Object.keys(store.schema || records[0] || {});

            const tableRows = records.map(r => {
                if (!hasMapping) return r;
                const row: any = {};
                headers.forEach(h => {
                     // For table, keys in mapping are the headers we want to show
                     const col = mapping[h]; 
                     row[h] = r[col];
                });
                return row;
            });

            return {
                ...widget,
                data: {
                    headers: headers,
                    rows: tableRows,
                    columnTypes: {} 
                }
            };

        case WidgetType.CHART:
            const chartData = records;
            const chartConfig = { ...widget.config };

            // Auto-detect dataKeys if missing to prevent "No data keys defined" error
            if (!chartConfig.dataKeys || chartConfig.dataKeys.length === 0) {
                 const potentialKeys = new Set<string>();

                 // Strategy 1: Look at Field Mapping
                 // The UI Agent often maps 'value', 'y', or 'data' to the metric column
                 if (Object.keys(mapping).length > 0) {
                     ['value', 'y', 'data', 'count', 'score', 'metric', 'amount'].forEach(key => {
                         if (mapping[key]) potentialKeys.add(mapping[key]);
                     });
                 }

                 // Strategy 2: Scan Data (Fallback or Supplement)
                 // Scan up to 10 rows to find keys that hold numeric values
                 if (potentialKeys.size === 0) {
                     const xKey = chartConfig.xAxisKey;
                     for (let i = 0; i < Math.min(chartData.length, 10); i++) {
                         const row = chartData[i];
                         if (!row) continue;
                         Object.keys(row).forEach(k => {
                             if (k === 'id' || k === xKey) return;
                             const val = row[k];
                             // Check if number or parsable string (handling potential nulls safely)
                             if (val !== null && val !== undefined && (typeof val === 'number' || (typeof val === 'string' && !isNaN(Number(val))))) {
                                 potentialKeys.add(k);
                             }
                         });
                     }
                 }

                 if (potentialKeys.size > 0) {
                     chartConfig.dataKeys = Array.from(potentialKeys);
                 }
            }

            return {
                ...widget,
                config: chartConfig,
                data: chartData
            };

        case WidgetType.KANBAN:
            // Group By Logic
            const groupBy = (widget.dataSource as any).groupByField || 'status';
            const mappedRecords = records.map(r => mapRecord(r));

            // Get unique groups
            const groups = Array.from(new Set(mappedRecords.map((r: any) => r[groupBy] || 'Uncategorized')));
            const columns = groups.map(group => ({
                id: String(group),
                title: String(group).toUpperCase(),
                tasks: mappedRecords
                    .filter((r: any) => (r[groupBy] || 'Uncategorized') === group)
                    .map((r: any) => ({
                        id: r.id || String(Math.random()),
                        content: r.content || r.title || r.name || "No Content",
                        tag: r.tag,
                        priority: r.priority,
                        dueDate: r.dueDate
                    }))
            }));

            return {
                ...widget,
                columns
            };

        default:
            return widget;
    }
};


export const WidgetRenderer: React.FC<WidgetRendererProps> = ({ widget, onMindmapNodeClick, isExpanded, projectData }) => {
  // Hydrate the widget data from the store if a dataSource is present
  const hydratedWidget = useMemo(() => {
     if (projectData && projectData.stores && widget.dataSource) {
         return hydrateWidget(widget, projectData.stores);
     }
     return widget;
  }, [widget, projectData]);

  if (!hydratedWidget) return null;

  switch (hydratedWidget.type) {
    case WidgetType.GANTT:
      return <GanttWidget title={hydratedWidget.title} tasks={hydratedWidget.tasks || []} />;
    case WidgetType.CHART:
      return <ChartWidget title={hydratedWidget.title} config={hydratedWidget.config} data={hydratedWidget.data || []} isExpanded={isExpanded} />;
    case WidgetType.KANBAN:
        return <KanbanWidget title={hydratedWidget.title} columns={hydratedWidget.columns || []} isExpanded={isExpanded} />;
    case WidgetType.TABLE:
        return <TableWidget title={hydratedWidget.title} data={hydratedWidget.data} />;
    case WidgetType.CODE:
        return <CodeWidget title={hydratedWidget.title} code={hydratedWidget.code} dataContext={projectData} />;
    case WidgetType.MINDMAP:
        return <MindmapWidget title={hydratedWidget.title} nodes={hydratedWidget.nodes} onNodeClick={onMindmapNodeClick} />;
    case WidgetType.METRICS:
        return <MetricsWidget title={hydratedWidget.title} items={hydratedWidget.contentItems || []} />;
    case WidgetType.RISK_MATRIX:
        return <RiskMatrixWidget title={hydratedWidget.title} risks={hydratedWidget.risks || []} />;
    case WidgetType.REFERENCES:
        return <ReferencesWidget title={hydratedWidget.title} items={hydratedWidget.contentItems || []} />;
    case WidgetType.MAP:
        return <MapWidget title={hydratedWidget.title} markers={hydratedWidget.markers || []} />;
    case WidgetType.ERROR:
        return <ErrorWidget title={hydratedWidget.title} error={hydratedWidget.error} />;
    default:
      return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Sidebar } from './components/Sidebar';
import { NodeView } from './components/NodeView';
import { ChatInput } from './components/Layout/ChatInput';
import { ProjectNode, ProjectState, ThinkingBudgetLevel, NodeData, ModelProvider, CustomModelConfig, RestorePoint } from './types';
import { generateNodeResponse } from './services/api';
import { ConfirmationModal } from './components/ConfirmationModal';
import { CleanupModal } from './components/CleanupModal';
import { SettingsModal } from './components/SettingsModal';
import { deepMerge } from './utils/helpers';

const INITIAL_ROOT_ID = 'root-1';

const DEFAULT_STATE: ProjectState = {
  rootId: INITIAL_ROOT_ID,
  currentNodeId: INITIAL_ROOT_ID,
  selectedModel: 'gemini-3-pro-preview',
  thinkingBudget: 'low',
  isGroundingEnabled: false,
  modelProvider: 'gemini',
  isGeminiEnabled: true,
  customModelConfig: { endpoint: 'http://localhost:11434/v1/chat/completions', modelName: 'llama3', apiKey: '' },
  nodes: {
    [INITIAL_ROOT_ID]: {
      id: INITIAL_ROOT_ID, parentId: null, timestamp: Date.now(), userInput: "Project Start: Initialize environment.", userAttachments: [], children: [], isLoading: false, processingStage: 'idle',
      data: { summary: "Project workspace initialized. Ready for planning.", keyPoints: ["Workspace created"], projectKnowledge: {}, projectData: { stores: [] } },
      visualization: { title: "Workspace Root", widgets: [] }, chat: [] 
    }
  }
};

const STORAGE_KEY = 'gemini_project_mind_db_v10';

const App: React.FC = () => {
  const [project, setProject] = useState<ProjectState>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (!saved) return DEFAULT_STATE;
      const parsed = JSON.parse(saved);
      if (parsed.nodes) {
        Object.keys(parsed.nodes).forEach(key => {
            const node = parsed.nodes[key];
            if (node.isLoading) {
                node.isLoading = false;
                node.processingStage = 'idle';
                if (!node.chat) node.chat = [];
                node.chat.push({ role: 'assistant', text: '⚠️ Generation was interrupted.', timestamp: Date.now() });
            }
            if (!node.data.projectData) node.data.projectData = { stores: [] };
        });
      }
      // Ensure compatibility with older state
      if (parsed.isGeminiEnabled === undefined) parsed.isGeminiEnabled = true;
      return parsed;
    } catch (e) { return DEFAULT_STATE; }
  });

  const [input, setInput] = useState('');
  const [editingNodeId, setEditingNodeId] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [attachments, setAttachments] = useState<{name: string, type: string, data: string}[]>([]);
  const [confirmDelete, setConfirmDelete] = useState<{ id: string } | null>(null);
  const [widgetToDelete, setWidgetToDelete] = useState<{nodeId: string, idx: number} | null>(null);
  const [showCleanupModal, setShowCleanupModal] = useState(false);
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => { localStorage.setItem(STORAGE_KEY, JSON.stringify(project)); }, [project]);

  const currentNode = project.nodes[project.currentNodeId] || project.nodes[project.rootId];
  const parentNode = currentNode?.parentId ? project.nodes[currentNode.parentId] : undefined;

  const handleSubmit = async (overrideInput?: string, subMode: 'branch' | 'chat' | 'synthesize' | 'refresh' | 'cleanup' = 'branch') => {
    const finalInput = overrideInput ?? input;
    if (isProcessing) return;
    // Allow empty input for cleanup and refresh/synthesize modes
    if (subMode !== 'synthesize' && subMode !== 'refresh' && subMode !== 'cleanup' && !finalInput.trim() && attachments.length === 0) return;

    setIsProcessing(true);
    if (abortControllerRef.current) abortControllerRef.current.abort();
    const controller = new AbortController();
    abortControllerRef.current = controller;

    const currentAttachments = [...attachments];
    // Cleanup is now a branching operation (new node) to preserve history
    const targetNodeId = (subMode === 'chat' || subMode === 'refresh' || (!!editingNodeId && subMode !== 'cleanup')) ? project.currentNodeId : uuidv4();

    if (!overrideInput) setInput('');
    setAttachments([]);
    setEditingNodeId(null);

    let updatedProject: ProjectState;
    const timestamp = Date.now();

    if (subMode === 'chat' || subMode === 'refresh' || project.currentNodeId === targetNodeId) {
      const node = project.nodes[targetNodeId];
      const newChat = [...(node.chat || [])];
      if (subMode === 'chat') newChat.push({ role: 'user', text: finalInput, timestamp, attachments: currentAttachments.length > 0 ? currentAttachments : undefined });
      updatedProject = { ...project, nodes: { ...project.nodes, [targetNodeId]: { ...node, chat: newChat, isLoading: true, processingStage: 'analyzing' } } };
    } else {
      const parent = project.nodes[project.currentNodeId];
      if (!parent) {
          console.error("Parent node not found during branching");
          setIsProcessing(false);
          return;
      }

      const newNode: ProjectNode = {
        id: targetNodeId, parentId: project.currentNodeId, timestamp, userInput: finalInput, userAttachments: currentAttachments, chat: [],
        data: { 
          summary: subMode === 'cleanup' ? "Consolidating history..." : "Initializing...", 
          keyPoints: [], 
          projectKnowledge: parent.data?.projectKnowledge || {}, 
          projectData: parent.data?.projectData || { stores: [] } 
        },
        visualization: { title: subMode === 'cleanup' ? "Consolidated State" : "New Branch", widgets: [] }, 
        children: [], 
        isLoading: true, 
        processingStage: 'analyzing'
      };

      const safeChildren = parent.children || [];

      updatedProject = { 
          ...project, 
          nodes: { 
              ...project.nodes, 
              [project.currentNodeId]: { ...parent, children: [...safeChildren, targetNodeId] }, 
              [targetNodeId]: newNode 
          }, 
          currentNodeId: targetNodeId 
      };
    }
    setProject(updatedProject);

    try {
      const apiCall = generateNodeResponse(targetNodeId, updatedProject, subMode, updatedProject.selectedModel, updatedProject.thinkingBudget, updatedProject.isGroundingEnabled, (stage) => {
              setProject(curr => ({ ...curr, nodes: { ...curr.nodes, [targetNodeId]: { ...curr.nodes[targetNodeId], processingStage: stage } } }));
      }, controller.signal);
      const response = await Promise.race([apiCall, new Promise<never>((_, rej) => setTimeout(() => rej(new Error("Timeout")), 180000))]);

      setProject(current => {
          const node = current.nodes[targetNodeId];
          let chat = [...(node.chat || [])];
          let updatedUserInput = node.userInput;
          if (subMode === 'cleanup') { 
              if (response.consolidatedUserIntent) updatedUserInput = response.consolidatedUserIntent; 
              chat = [{ role: 'assistant', text: response.chatReply, timestamp: Date.now(), groundingSources: response.groundingSources, visualizationSnapshot: response.updatedVisualization, dataSnapshot: response.updatedData }]; 
          }
          else chat.push({ role: 'assistant', text: response.chatReply, timestamp: Date.now(), groundingSources: response.groundingSources, visualizationSnapshot: response.updatedVisualization, dataSnapshot: response.updatedData });
          return { ...current, nodes: { ...current.nodes, [targetNodeId]: { ...node, userInput: updatedUserInput, isLoading: false, processingStage: 'idle', chat, data: response.updatedData, visualization: response.updatedVisualization, restorePoint: undefined, debugInfo: { ...response.debugInfo, response: `Thought Process: ${response.thoughtProcess}\n\n${response.debugInfo?.response || ''}` } } } };
      });
    } catch (err: any) {
      const isAbort = err.message === "Request cancelled by user.";
      setProject(current => { const node = current.nodes[targetNodeId]; const chat = [...(node.chat || [])]; chat.push({ role: 'assistant', text: isAbort ? '⛔ Request cancelled.' : `⚠️ Error: ${err.message}`, timestamp: Date.now() }); return { ...current, nodes: { ...current.nodes, [targetNodeId]: { ...node, chat, isLoading: false, processingStage: 'idle' } } }; });
    } finally { abortControllerRef.current = null; setIsProcessing(false); }
  };

  const handlePaste = async (e: React.ClipboardEvent) => {
    const items = e.clipboardData.items;
    const newAtts: {name: string, type: string, data: string}[] = [];
    for (let i = 0; i < items.length; i++) { if (items[i].type.indexOf('image') !== -1) { const file = items[i].getAsFile(); if (file) { const dataUrl = await new Promise<string>((res) => { const reader = new FileReader(); reader.onload = () => res(reader.result as string); reader.readAsDataURL(file); }); newAtts.push({ name: `pasted-${Date.now()}-${i}`, type: file.type, data: dataUrl }); } } }
    if (newAtts.length > 0) setAttachments(prev => [...prev, ...newAtts]);
  };

  return (
    <div className="flex h-screen bg-white text-slate-900 overflow-hidden">
      <ConfirmationModal isOpen={!!confirmDelete} onConfirm={() => confirmDelete && setProject(prev => { const newNodes = { ...prev.nodes }; const nodeToDelete = newNodes[confirmDelete.id]; if (!nodeToDelete) return prev; if (nodeToDelete.parentId && newNodes[nodeToDelete.parentId]) { const parent = newNodes[nodeToDelete.parentId]; newNodes[nodeToDelete.parentId] = { ...parent, children: (parent.children || []).filter(cid => cid !== confirmDelete.id) }; } const collect = (tid: string): string[] => { const n = newNodes[tid]; if (!n) return []; let desc = [tid]; (n.children || []).forEach(cid => { desc = [...desc, ...collect(cid)]; }); return desc; }; const ids = collect(confirmDelete.id); ids.forEach(tid => { delete newNodes[tid]; }); let nextId = prev.currentNodeId; if (ids.includes(prev.currentNodeId)) nextId = nodeToDelete.parentId && newNodes[nodeToDelete.parentId] ? nodeToDelete.parentId : prev.rootId; return { ...prev, nodes: newNodes, currentNodeId: nextId }; })} onCancel={() => setConfirmDelete(null)} title="Delete Branch" message="This action cannot be undone." />
      <ConfirmationModal isOpen={!!widgetToDelete} onConfirm={() => setProject(prev => { const node = prev.nodes[widgetToDelete!.nodeId]; if (!node || !node.visualization?.widgets) return prev; const newWidgets = [...node.visualization.widgets]; newWidgets.splice(widgetToDelete!.idx, 1); return { ...prev, nodes: { ...prev.nodes, [widgetToDelete!.nodeId]: { ...node, visualization: { ...node.visualization, widgets: newWidgets } } } }; })} onCancel={() => setWidgetToDelete(null)} title="Delete Widget" message="Remove from history?" />

      <div className={`transition-all duration-300 ease-in-out border-r border-slate-200 bg-white flex shrink-0 ${isSidebarOpen ? 'w-64' : 'w-0'}`} style={{ overflow: isSidebarOpen ? 'visible' : 'hidden' }}>
        <Sidebar 
          nodes={project.nodes} rootId={project.rootId} currentNodeId={project.currentNodeId} 
          onSelectNode={(id) => { setProject(prev => ({ ...prev, currentNodeId: id })); setEditingNodeId(null); }} 
          onDeleteNode={(id) => { if (id !== project.rootId) setConfirmDelete({ id }); }} 
          onImport={setProject} 
          onModelChange={(m) => setProject(prev => ({ ...prev, selectedModel: m }))} 
          onBudgetChange={(l) => setProject(prev => ({ ...prev, thinkingBudget: l }))} 
          onGroundingToggle={(e) => setProject(prev => ({ ...prev, isGroundingEnabled: e }))} 
          onProviderChange={(p) => setProject(prev => ({ ...prev, modelProvider: p }))} 
          onCustomConfigChange={(c) => setProject(prev => ({ ...prev, customModelConfig: { ...prev.customModelConfig, ...c } }))} 
          onOpenSettings={() => setShowSettingsModal(true)}
          projectState={project} 
          onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} 
          isOpen={isSidebarOpen} 
        />
      </div>

      <main className="flex-1 flex flex-col relative min-w-0 bg-white">
        <NodeView 
          node={currentNode} 
          parentNode={parentNode} 
          projectState={project} 
          onSelectNode={(id) => { setProject(prev => ({ ...prev, currentNodeId: id })); setEditingNodeId(null); }} 
          onRegenerate={(txt) => { setInput(txt); setEditingNodeId(currentNode.id); }} 
          onSynthesize={(topic) => handleSubmit(topic, 'synthesize')} 
          onRefresh={() => handleSubmit(undefined, 'refresh')} 
          onMindmapNodeClick={(n) => handleSubmit(`Expand: ${n.label}`, 'branch')} 
          onDeleteChatMessage={(i) => setProject(prev => { 
            const node = prev.nodes[prev.currentNodeId]; 
            if (!node?.chat) return prev; 
            const newChat = [...node.chat]; 
            newChat.splice(i, 1); 
            return { ...prev, nodes: { ...prev.nodes, [prev.currentNodeId]: { ...node, chat: newChat } } }; 
          })} 
          onDeleteWidget={(nodeId, idx) => setWidgetToDelete({ nodeId, idx })} 
          onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} 
          isSidebarOpen={isSidebarOpen} 
          onUpdateNodeData={(nid, data) => setProject(prev => { 
            const node = prev.nodes[nid]; 
            if (!node) return prev; 
            return { ...prev, nodes: { ...prev.nodes, [nid]: { ...node, data: { ...node.data, ...data } } } }; 
          })} 
          onRevertState={(i) => setProject(prev => { 
            const node = prev.nodes[prev.currentNodeId]; 
            if (!node?.chat[i]?.dataSnapshot) return prev; 
            const target = node.chat[i]; 
            return { ...prev, nodes: { ...prev.nodes, [prev.currentNodeId]: { ...node, chat: node.chat.slice(0, i + 1), data: JSON.parse(JSON.stringify(target.dataSnapshot)), visualization: JSON.parse(JSON.stringify(target.visualizationSnapshot)), isLoading: false, processingStage: 'idle' } } }; 
          })} 
          onShowCleanupModal={() => setShowCleanupModal(true)} 
          onUndoCleanup={() => setProject(prev => { 
            const node = prev.nodes[prev.currentNodeId]; 
            if (!node?.restorePoint) return prev; 
            return { ...prev, nodes: { ...prev.nodes, [node.id]: { ...node, chat: node.restorePoint.chat, data: node.restorePoint.data, visualization: node.restorePoint.visualization, userInput: node.restorePoint.userInput, restorePoint: undefined } } }; 
          })} 
        />
        <ChatInput input={input} setInput={setInput} attachments={attachments} setAttachments={setAttachments} isProcessing={isProcessing} onSubmit={handleSubmit} onStop={() => abortControllerRef.current?.abort()} editingNodeId={editingNodeId} onPaste={handlePaste} />
      </main>

      <CleanupModal 
        isOpen={showCleanupModal}
        onConfirm={(focus) => { setShowCleanupModal(false); handleSubmit(focus, 'cleanup'); }}
        onCancel={() => setShowCleanupModal(false)}
      />

      <SettingsModal 
        isOpen={showSettingsModal} 
        onClose={() => setShowSettingsModal(false)}
        projectState={project}
        onToggleGemini={(enabled) => setProject(prev => ({ ...prev, isGeminiEnabled: enabled, modelProvider: enabled ? prev.modelProvider : 'custom' }))}
      />
    </div>
  );
};

export default App;

