  mode: 'branch' | 'chat' | 'synthesize' | 'refresh' | 'cleanup',
  modelName: string, // Used for Gemini
  thinkingBudget: ThinkingBudgetLevel,
  isGroundingEnabled: boolean,
  onProgress?: (stage: ProcessingStage) => void,
  signal?: AbortSignal
): Promise<AIResponse> => {
  const node = projectState.nodes[targetNodeId];
  if (!node) throw new Error("Node not found");

  const checkAbort = () => {
    if (signal?.aborted) throw new Error("Request cancelled by user.");
  };

  checkAbort();

  // --- PREPARE HISTORY ---
  const history: ProjectNode[] = [];
  let curr: ProjectNode | undefined = node;
  while (curr) {
    history.unshift(curr);
    curr = curr.parentId ? projectState.nodes[curr.parentId] : undefined;
  }

  // --- DETERMINE BASELINE STATE ---
  let lastKnownKnowledge = {};
  let lastKnownData: { stores: DataStore[] } = { stores: [] };

  history.forEach((n) => {
    if (n.data?.projectKnowledge && Object.keys(n.data.projectKnowledge).length > 0) {
        lastKnownKnowledge = n.data.projectKnowledge;
    }
    if (n.data?.projectData) {
        lastKnownData = n.data.projectData;
    }
  });

  // Current node context overrides
  if (node.data?.projectKnowledge && Object.keys(node.data.projectKnowledge).length > 0) {
      lastKnownKnowledge = node.data.projectKnowledge;
  }
  if (node.data?.projectData) {
      lastKnownData = node.data.projectData;
  }

  // ==========================================
  // PHASE 1: DATA ARCHITECT
  // ==========================================
  onProgress?.('analyzing');
  checkAbort();

  const dataPrompt = constructDataPrompt(history, node, lastKnownKnowledge, lastKnownData, mode);
  let dataResult: any;
  let groundingSources: GroundingSource[] = [];

  if (projectState.modelProvider === 'gemini') {
      const budgetMap: Record<ThinkingBudgetLevel, number> = { low: 512, medium: 4096, high: 32768 };
      const isMapsModel = modelName.includes("2.5");
      const tools: any[] = [];
      if (isGroundingEnabled) {
          tools.push({ googleSearch: {} });
          if (isMapsModel) tools.push({ googleMaps: {} });
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const dataConfig: any = {
          systemInstruction: getDataSystemInstruction(isGroundingEnabled),
          tools: tools,
          thinkingConfig: { thinkingBudget: budgetMap[thinkingBudget] },
          responseMimeType: "application/json",
          responseSchema: dataAgentSchema
      };

      const dataResponse = await wrapWithAbort(ai.models.generateContent({
          model: modelName,
          contents: { parts: dataPrompt },
          config: dataConfig
      }), signal) as GenerateContentResponse;

      checkAbort();
      dataResult = safeParse(dataResponse.text || "{}");

      // Extract Grounding
      const groundingChunks = dataResponse.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (groundingChunks) {
          groundingChunks.forEach((chunk: any) => {
              if (chunk.web?.uri && chunk.web?.title) groundingSources.push({ title: chunk.web.title, uri: chunk.web.uri });
              if (chunk.maps?.uri && chunk.maps?.title) groundingSources.push({ title: `📍 ${chunk.maps.title}`, uri: chunk.maps.uri });
          });
      }
  } else {
      // CUSTOM PROVIDER
      const { endpoint, modelName: customModel, apiKey } = projectState.customModelConfig;
      if (!endpoint || !customModel) throw new Error("Missing Custom API Configuration");

      dataResult = await callCustomAI(
          endpoint,
          customModel,
          apiKey,
          getDataSystemInstruction(false), // Grounding disabled for custom
          history,
          dataPrompt,
          dataAgentSchema,
          signal
      );
  }

  // ==========================================
  // PHASE 1.5: APPLY DATA UPDATES (IN-MEMORY)
  // ==========================================
  onProgress?.('updating_data');
  checkAbort();

  if (!dataResult.updatedData) dataResult.updatedData = { summary: "No summary", keyPoints: [] };

  // Parse nested JSON strings if present
  if (dataResult.updatedData.projectKnowledgeJson) {
      try { 
          // Handle loose JSON strings from some models
          dataResult.updatedData.projectKnowledge = parseOrRaw(dataResult.updatedData.projectKnowledgeJson) || dataResult.updatedData.projectKnowledge;
      } catch(e) {}
  } else {
      dataResult.updatedData.projectKnowledge = lastKnownKnowledge;
  }

  // Execute Store Operations
  let updatedStores = lastKnownData.stores ? [...lastKnownData.stores] : [];
  if (dataResult.updatedData.projectDataUpdates && Array.isArray(dataResult.updatedData.projectDataUpdates)) {
      dataResult.updatedData.projectDataUpdates.forEach((op: any) => {
          const existingIdx = updatedStores.findIndex(s => s.id === op.storeId);

          let schemaMap = parseOrRaw(op.schemaJson) || {};
          let recordsArr = parseOrRaw(op.recordsJson) || [];

          // Helper for Upsert Logic
          const upsertRecords = (currentRecords: any[], newRecords: any[], schema: any) => {
              const mergedRecords = [...currentRecords];
              // SMART DE-DUPLICATION LOGIC
              const commonKeyFields = ['name', 'title', 'label', 'content', 'task', 'feature', 'ticket', 'item'];
              const schemaKeys = Object.keys(schema || {});
              const businessKey = commonKeyFields.find(k => schemaKeys.includes(k) || (currentRecords.length > 0 && k in currentRecords[0]));

              newRecords.forEach((newRec: any) => {
                  let recordId = newRec.id;

                  if (!recordId && businessKey && newRec[businessKey]) {
                      const candidates = mergedRecords.filter(r => r[businessKey] === newRec[businessKey]);
                      if (candidates.length === 1) {
                          recordId = candidates[0].id;
                      }
                  }

                  if (!recordId) {
                       recordId = `gen-${Math.random().toString(36).substr(2, 9)}`;
                       newRec.id = recordId;
                  } else {
                      newRec.id = recordId;
                  }

                  const matchIdx = mergedRecords.findIndex(r => r.id === recordId);
                  if (matchIdx !== -1) {
                      mergedRecords[matchIdx] = { ...mergedRecords[matchIdx], ...newRec };
                  } else {
                      mergedRecords.push(newRec);
                  }
              });
              return mergedRecords;
          };

          if (op.operation === 'DELETE_STORE') {
              if (existingIdx !== -1) updatedStores.splice(existingIdx, 1);
          } 
          else if (op.operation === 'CREATE_OR_UPDATE_STORE') {
              if (existingIdx !== -1) {
                  // UPDATE EXISTING
                  const store = updatedStores[existingIdx];
                  const newSchema = (Object.keys(schemaMap).length > 0) ? schemaMap : store.schema;

                  // If records provided in CREATE/UPDATE op, apply them
                  const finalRecords = (recordsArr.length > 0) 
                      ? upsertRecords(store.records, recordsArr, newSchema)
                      : store.records;

                  updatedStores[existingIdx] = {
                      ...store,
                      name: op.name || store.name,
                      schema: newSchema,
                      records: finalRecords
                  };
              } else {
                  // CREATE NEW
                  updatedStores.push({
                      id: op.storeId,
                      name: op.name || op.storeId,
                      schema: schemaMap,
                      records: recordsArr // Use records if provided in creation
                  });
              }
          } 
          else if (op.operation === 'UPSERT_RECORDS') {
              if (existingIdx !== -1) {
                  const store = updatedStores[existingIdx];
                  updatedStores[existingIdx] = { 
                      ...store, 
                      records: upsertRecords(store.records, recordsArr, store.schema) 
                  };
              } else {
                  // Implicit Create if missing
                  updatedStores.push({
                      id: op.storeId,
                      name: op.name || op.storeId,
                      schema: schemaMap,
                      records: recordsArr
                  });
              }
          }
          else if (op.operation === 'DELETE_RECORDS') {
              if (existingIdx !== -1) {
                  const store = updatedStores[existingIdx];
                  const idsToDelete = op.recordIds || [];
                  const filteredRecords = store.records.filter(r => !idsToDelete.includes(r.id));
                  updatedStores[existingIdx] = { ...store, records: filteredRecords };
              }
          }
      });
  }

  const nextDataState = {
      stores: updatedStores
  };

  dataResult.updatedData.projectData = nextDataState;

  // ==========================================
  // PHASE 2: UI DESIGNER
  // ==========================================
  onProgress?.('designing_ui');
  checkAbort();

  const uiPrompt = constructUIPrompt(node.userInput, nextDataState, dataResult.thoughtProcess);
  let uiResult;

  try {
      if (projectState.modelProvider === 'gemini') {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const uiConfig: any = {
              systemInstruction: getUISystemInstruction(),
              thinkingConfig: { thinkingBudget: 1024 }, 
              responseMimeType: "application/json",
              responseSchema: uiAgentSchema
          };

          const uiResponse = await wrapWithAbort(ai.models.generateContent({
              model: modelName, 
              contents: { parts: uiPrompt },
              config: uiConfig
          }), signal) as GenerateContentResponse;
          uiResult = safeParse(uiResponse.text || "{}");
      } else {
          // CUSTOM PROVIDER
          const { endpoint, modelName: customModel, apiKey } = projectState.customModelConfig;
          uiResult = await callCustomAI(
              endpoint,
              customModel,
              apiKey,
              getUISystemInstruction(),
              [], // UI Agent doesn't need history, just the prompt constructed from Data Agent output
              uiPrompt,
              uiAgentSchema,
              signal
          );
      }
  } catch (err: any) {
      if (err.message === "Request cancelled by user.") throw err;
      console.error("UI Agent Failed", err);
      uiResult = { updatedVisualization: { title: "Data Only", widgets: [] } };
  }

  // ==========================================
  // MERGE & SANITIZE
  // ==========================================
  onProgress?.('rendering');
  checkAbort();

  if (!uiResult.updatedVisualization) uiResult.updatedVisualization = { title: "Visualization Error", widgets: [] };

  if (groundingSources.length > 0) {
      const hasRefs = uiResult.updatedVisualization.widgets?.some((w: any) => w.type === WidgetType.REFERENCES);
      if (!hasRefs) {
          if (!uiResult.updatedVisualization.widgets) uiResult.updatedVisualization.widgets = [];
          uiResult.updatedVisualization.widgets.push({
              type: WidgetType.REFERENCES,
              title: "Research & Locations",
              contentItems: groundingSources
          });
      }
  }

  if (uiResult.updatedVisualization.widgets) {
      uiResult.updatedVisualization.widgets = uiResult.updatedVisualization.widgets.map(validateAndSanitizeWidget);
  }

  return {
      updatedData: dataResult.updatedData,
      updatedVisualization: uiResult.updatedVisualization,
      chatReply: dataResult.chatReply || "Processing complete.",
      thoughtProcess: `${dataResult.thoughtProcess}\n\n[UI Designer]: ${uiResult.thoughtProcess || 'Generated widgets based on data.'}`,
      groundingSources: groundingSources.length > 0 ? groundingSources : undefined,
      consolidatedUserIntent: dataResult.consolidatedUserIntent,
      debugInfo: {
          timestamp: Date.now(),
          request: {
              model: projectState.modelProvider === 'gemini' ? modelName : projectState.customModelConfig.modelName,
              prompt: "Multi-step agent chain execution",
              budget: projectState.thinkingBudget === 'low' ? 512 : projectState.thinkingBudget === 'medium' ? 4096 : 32768,
              grounding: isGroundingEnabled
          },
          response: `DATA AGENT:\n${JSON.stringify(dataResult, null, 2)}\n\nUI AGENT:\n${JSON.stringify(uiResult, null, 2)}`
      }
  };
};

import React, { useMemo } from 'react';
import { WidgetData, WidgetType, MindmapNode, DataStore } from '../../types';
import { GanttWidget } from './GanttWidget';
import { ChartWidget } from './ChartWidget';
import { KanbanWidget } from './KanbanWidget';
import { MindmapWidget } from './MindmapWidget';
import { MapWidget } from './MapWidget';
import { MetricsWidget } from './MetricsWidget';
import { RiskMatrixWidget } from './RiskMatrixWidget';
import { ReferencesWidget } from './ReferencesWidget';
import { ErrorWidget } from './ErrorWidget';
import { CodeWidget } from './CodeWidget';
import { TableWidget } from './TableWidget';

interface WidgetRendererProps {
  widget: WidgetData;
  onMindmapNodeClick?: (node: MindmapNode) => void;
  isExpanded?: boolean;
  projectData?: { stores: DataStore[] }; // Pass the full project data context
}

// --- HYDRATION HELPERS ---

const hydrateWidget = (widget: WidgetData, stores: DataStore[]): any => {
    // If no data source or invalid data source, return widget as is (Legacy mode)
    if (!widget.dataSource || !widget.dataSource.storeId) return widget;

    const store = stores.find(s => s.id === widget.dataSource!.storeId);
    if (!store) {
        console.warn(`Widget ${widget.title} referenced missing store: ${widget.dataSource!.storeId}`);
        return widget;
    }

    // Convert array-based mapping to Record<widgetKey, storeColumn>
    const mappingArray = widget.dataSource!.fieldMapping || [];
    const mapping: Record<string, string> = {};
    if (Array.isArray(mappingArray)) {
        mappingArray.forEach(m => {
            if (m.widgetKey && m.storeColumn) {
                mapping[m.widgetKey] = m.storeColumn;
            }
        });
    } else {
        // Fallback for single object or legacy map
        const asObj = mappingArray as any;
        if (asObj.widgetKey && asObj.storeColumn) {
             mapping[asObj.widgetKey] = asObj.storeColumn;
        } else {
             Object.assign(mapping, mappingArray);
        }
    }

    const records = store.records || [];

    // Helper to map a record using the field mapping
    const mapRecord = (record: any) => {
        const result: any = { ...record }; // Keep original fields for flexibility
        Object.entries(mapping).forEach(([widgetKey, storeColumn]) => {
            if (storeColumn && record[storeColumn] !== undefined) {
                result[widgetKey] = record[storeColumn];
            }
        });
        return result;
    };

    switch (widget.type) {
        case WidgetType.GANTT:
            return {
                ...widget,
                tasks: records.map(r => {
                    const mapped = mapRecord(r);

                    // Robust fallback logic for common fields if mapping misses them
                    // This handles cases where models use keys like 'start_date' but don't map them to 'start'
                    const findVal = (keys: string[]) => {
                        for (const k of keys) {
                            if (mapped[k] !== undefined && mapped[k] !== null) return mapped[k];
                        }
                        // Case-insensitive fallback
                        const lowerKeys = keys.map(k => k.toLowerCase());
                        for (const k of Object.keys(mapped)) {
                             if (lowerKeys.includes(k.toLowerCase()) && mapped[k] !== undefined && mapped[k] !== null) return mapped[k];
                        }
                        return undefined;
                    };

                    const name = mapped.name || findVal(['task', 'title', 'label', 'content', 'item', 'feature']) || "Untitled Task";
                    const start = mapped.start || findVal(['start_date', 'startDate', 'begin', 'init', 'created_at']);
                    const end = mapped.end || findVal(['end_date', 'endDate', 'finish', 'due', 'dueDate', 'deadline', 'target_date']);
                    const progress = mapped.progress !== undefined ? mapped.progress : findVal(['percent', 'percentage', 'completion', 'done']);
                    const status = mapped.status || findVal(['state', 'stage']);
                    const owner = mapped.owner || findVal(['assignee', 'user', 'who', 'lead']);

                    return {
                        id: mapped.id || r.id || String(Math.random()),
                        name: String(name),
                        start: start,
                        end: end,
                        progress: progress ? Number(progress) : 0,
                        owner: owner,
                        status: status,
                        isEstimated: mapped.isEstimated,
                        dependencies: mapped.dependencies
                    };
                })
            };

        case WidgetType.METRICS:
            return {
                ...widget,
                contentItems: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        label: mapped.label || "Metric",
                        value: mapped.value,
                        trend: mapped.trend,
                        status: mapped.status,
                        description: mapped.description
                    };
                })
            };

        case WidgetType.REFERENCES:
            return {
                ...widget,
                contentItems: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        title: mapped.title || "Reference",
                        uri: mapped.uri || "#",
                    };
                })
            };

        case WidgetType.RISK_MATRIX:
            return {
                ...widget,
                risks: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        id: mapped.id || r.id,
                        label: mapped.label || "Risk",
                        impact: Number(mapped.impact),
                        likelihood: Number(mapped.likelihood),
                        mitigation: mapped.mitigation
                    };
                })
            };

        case WidgetType.MAP:
            return {
                ...widget,
                markers: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        id: mapped.id || r.id,
                        label: mapped.label || "Location",
                        address: mapped.address,
                        latitude: Number(mapped.latitude),
                        longitude: Number(mapped.longitude),
                        description: mapped.description,
                        type: mapped.type
                    };
                })
            };

        case WidgetType.TABLE:
            // For tables, if mapping exists, we use it to construct the view
            const hasMapping = Object.keys(mapping).length > 0;
            // If mapping exists, the headers are the widgetKeys. Otherwise use store schema.
            const headers = hasMapping ? Object.keys(mapping) : Object.keys(store.schema || records[0] || {});

            const tableRows = records.map(r => {
                if (!hasMapping) return r;
                const row: any = {};
                headers.forEach(h => {
                     // For table, keys in mapping are the headers we want to show
                     const col = mapping[h]; 
                     row[h] = r[col];
                });
                return row;
            });

            return {
                ...widget,
                data: {
                    headers: headers,
                    rows: tableRows,
                    columnTypes: {} 
                }
            };

        case WidgetType.CHART:
            const chartData = records;
            const chartConfig = { ...widget.config };

            // Auto-detect dataKeys if missing to prevent "No data keys defined" error
            if (!chartConfig.dataKeys || chartConfig.dataKeys.length === 0) {
                 const potentialKeys = new Set<string>();

                 // Strategy 1: Look at Field Mapping
                 // The UI Agent often maps 'value', 'y', or 'data' to the metric column
                 if (Object.keys(mapping).length > 0) {
                     ['value', 'y', 'data', 'count', 'score', 'metric', 'amount'].forEach(key => {
                         if (mapping[key]) potentialKeys.add(mapping[key]);
                     });
                 }

                 // Strategy 2: Scan Data (Fallback or Supplement)
                 // Scan up to 10 rows to find keys that hold numeric values
                 if (potentialKeys.size === 0) {
                     const xKey = chartConfig.xAxisKey;
                     for (let i = 0; i < Math.min(chartData.length, 10); i++) {
                         const row = chartData[i];
                         if (!row) continue;
                         Object.keys(row).forEach(k => {
                             if (k === 'id' || k === xKey) return;
                             const val = row[k];
                             // Check if number or parsable string (handling potential nulls safely)
                             if (val !== null && val !== undefined && (typeof val === 'number' || (typeof val === 'string' && !isNaN(Number(val))))) {
                                 potentialKeys.add(k);
                             }
                         });
                     }
                 }

                 if (potentialKeys.size > 0) {
                     chartConfig.dataKeys = Array.from(potentialKeys);
                 }
            }

            return {
                ...widget,
                config: chartConfig,
                data: chartData
            };

        case WidgetType.KANBAN:
            // Group By Logic
            const groupBy = (widget.dataSource as any).groupByField || 'status';
            const mappedRecords = records.map(r => mapRecord(r));

            // Get unique groups
            const groups = Array.from(new Set(mappedRecords.map((r: any) => r[groupBy] || 'Uncategorized')));
            const columns = groups.map(group => ({
                id: String(group),
                title: String(group).toUpperCase(),
                tasks: mappedRecords
                    .filter((r: any) => (r[groupBy] || 'Uncategorized') === group)
                    .map((r: any) => ({
                        id: r.id || String(Math.random()),
                        content: r.content || r.title || r.name || r.task || "No Content",
                        tag: r.tag,
                        priority: r.priority,
                        dueDate: r.dueDate
                    }))
            }));

            return {
                ...widget,
                columns
            };

        default:
            return widget;
    }
};


export const WidgetRenderer: React.FC<WidgetRendererProps> = ({ widget, onMindmapNodeClick, isExpanded, projectData }) => {
  // Hydrate the widget data from the store if a dataSource is present
  const hydratedWidget = useMemo(() => {
     if (projectData && projectData.stores && widget.dataSource) {
         return hydrateWidget(widget, projectData.stores);
     }
     return widget;
  }, [widget, projectData]);

  if (!hydratedWidget) return null;

  switch (hydratedWidget.type) {
    case WidgetType.GANTT:
      return <GanttWidget title={hydratedWidget.title} tasks={hydratedWidget.tasks || []} />;
    case WidgetType.CHART:
      return <ChartWidget title={hydratedWidget.title} config={hydratedWidget.config} data={hydratedWidget.data || []} isExpanded={isExpanded} />;
    case WidgetType.KANBAN:
        return <KanbanWidget title={hydratedWidget.title} columns={hydratedWidget.columns || []} isExpanded={isExpanded} />;
    case WidgetType.TABLE:
        return <TableWidget title={hydratedWidget.title} data={hydratedWidget.data} />;
    case WidgetType.CODE:
        return <CodeWidget title={hydratedWidget.title} code={hydratedWidget.code} dataContext={projectData} />;
    case WidgetType.MINDMAP:
        return <MindmapWidget title={hydratedWidget.title} nodes={hydratedWidget.nodes} onNodeClick={onMindmapNodeClick} />;
    case WidgetType.METRICS:
        return <MetricsWidget title={hydratedWidget.title} items={hydratedWidget.contentItems || []} />;
    case WidgetType.RISK_MATRIX:
        return <RiskMatrixWidget title={hydratedWidget.title} risks={hydratedWidget.risks || []} />;
    case WidgetType.REFERENCES:
        return <ReferencesWidget title={hydratedWidget.title} items={hydratedWidget.contentItems || []} />;
    case WidgetType.MAP:
        return <MapWidget title={hydratedWidget.title} markers={hydratedWidget.markers || []} />;
    case WidgetType.ERROR:
        return <ErrorWidget title={hydratedWidget.title} error={hydratedWidget.error} />;
    default:
      return null;
  }
};

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { 
  ProjectState, 
  WidgetType, 
  AIResponse, 
  ThinkingBudgetLevel, 
  ProjectNode,
  GroundingSource,
  DataStore,
  ProcessingStage,
  ChatMessage
} from "../types";
import { validateAndSanitizeWidget } from "./sanitizer";
import { 
    getDataSystemInstruction, 
    constructDataPrompt, 
    dataAgentSchema,
    getUISystemInstruction,
    constructUIPrompt,
    uiAgentSchema
} from "./prompts";

// Helper to parse loose JSON
const safeParse = (jsonText: string) => {
    let parsed;
    try {
        parsed = JSON.parse(jsonText);
    } catch (e) {
        // Try to find the JSON block
        const match = jsonText.match(/\{[\s\S]*\}/);
        if (match) {
            try { parsed = JSON.parse(match[0]); } catch(e2) {}
        }
    }

    if (!parsed) throw new Error("Response was not valid JSON");

    // UNWRAP LOGIC: Fix for models that output the schema definition populated with data
    // Pattern: { type: "OBJECT", properties: { ...data... } }
    if (parsed.properties && !parsed.thoughtProcess) {
        // Check if properties contains the fields we expect 
        // We use 'thoughtProcess' as the canary since it's in both Data and UI schemas
        if (parsed.properties.thoughtProcess) {
            return parsed.properties;
        }
    }

    return parsed;
};

// Helper to handle mixed string/object inputs from models
const parseOrRaw = (input: any): any => {
    if (input === null || input === undefined) return null;
    if (typeof input === 'object') return input;

    if (typeof input === 'string') {
        const tryParse = (s: string) => {
             try { return JSON.parse(s); } catch(e) { return undefined; }
        }

        // 1. Try direct parse
        let result = tryParse(input);

        // 2. If failed, try cleaning escaped quotes (common model error: "[{\"key\":...}]")
        if (result === undefined) {
             // Replace \" with " and \\ with \ to fix common over-escaping
             const cleaned = input
                .replace(/\\"/g, '"')  // Unescape quotes
                .replace(/\\\\/g, '\\'); // Unescape backslashes

             result = tryParse(cleaned);
        }

        // 3. If result is a string (double encoded), recurse
        if (typeof result === 'string') {
            const trimmed = result.trim();
            if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
                 return parseOrRaw(result);
            }
        }

        return result !== undefined ? result : null;
    }

    return input;
};

// Helper to validate structure against expectations
const validateResponse = (data: any, type: 'data' | 'ui') => {
    if (typeof data !== 'object' || data === null) throw new Error("Response must be an object");

    if (type === 'data') {
        // Data Agent Validation
        if (!data.thoughtProcess || typeof data.thoughtProcess !== 'string') {
            throw new Error("Missing or invalid 'thoughtProcess' (string)");
        }
        if (!data.chatReply || typeof data.chatReply !== 'string') {
            throw new Error("Missing or invalid 'chatReply' (string)");
        }
        if (!data.updatedData || typeof data.updatedData !== 'object') {
            throw new Error("Missing or invalid 'updatedData' (object)");
        }
        // Deep check updatedData
        if (!data.updatedData.summary || typeof data.updatedData.summary !== 'string') {
            throw new Error("Missing 'updatedData.summary'");
        }
        if (!Array.isArray(data.updatedData.keyPoints)) {
            throw new Error("Missing 'updatedData.keyPoints' (array)");
        }
        if (data.updatedData.projectDataUpdates && !Array.isArray(data.updatedData.projectDataUpdates)) {
             throw new Error("'projectDataUpdates' must be an array");
        }
    } else {
        // UI Agent Validation
         if (!data.thoughtProcess || typeof data.thoughtProcess !== 'string') {
             throw new Error("Missing 'thoughtProcess'");
         }
         if (!data.updatedVisualization || typeof data.updatedVisualization !== 'object') {
             throw new Error("Missing 'updatedVisualization' (object)");
         }
         if (!data.updatedVisualization.title || typeof data.updatedVisualization.title !== 'string') {
             throw new Error("Missing 'updatedVisualization.title'");
         }
         if (data.updatedVisualization.widgets && !Array.isArray(data.updatedVisualization.widgets)) {
             throw new Error("'updatedVisualization.widgets' must be an array");
         }
    }
};

// Helper to wrap promise with cancellation
const wrapWithAbort = <T>(promise: Promise<T>, signal?: AbortSignal): Promise<T> => {
    if (!signal) return promise;
    return Promise.race([
        promise,
        new Promise<T>((_, reject) => {
            const abortHandler = () => reject(new Error("Request cancelled by user."));
            if (signal.aborted) {
                abortHandler();
            } else {
                signal.addEventListener('abort', abortHandler);
            }
        })
    ]);
};

// Helper for Custom API Calls (OpenAI Compatible)
const callCustomAI = async (
    endpoint: string,
    modelName: string,
    apiKey: string | undefined,
    systemInstruction: string,
    history: ProjectNode[],
    promptParts: any[], // From constructDataPrompt/constructUIPrompt
    schema: any,
    signal?: AbortSignal
): Promise<any> => {

    const messages: { role: string; content: string }[] = [];

    const schemaString = JSON.stringify(schema, null, 2);
    const fullSystemInstruction = `${systemInstruction}\n\nIMPORTANT: You must output strictly valid JSON matching this schema:\n${schemaString}\n\nDo not include markdown formatting like \`\`\`json in your response. Just the raw JSON.`;
    messages.push({ role: 'system', content: fullSystemInstruction });

    let userContent = "";
    promptParts.forEach(p => {
        if (p.text) userContent += p.text + "\n";
    });

    messages.push({ role: 'user', content: userContent });

    const headers: Record<string, string> = {
        'Content-Type': 'application/json'
    };
    if (apiKey) {
        headers['Authorization'] = `Bearer ${apiKey}`;
    }

    const body = {
        model: modelName,
        messages: messages,
        temperature: 0.7,
        max_tokens: 4000,
        response_format: { type: "json_object" }
    };

    const response = await fetch(endpoint, {
        method: 'POST',
        headers,
        body: JSON.stringify(body),
        signal
    });

    if (!response.ok) {
        const errText = await response.text();
        throw new Error(`Custom API Error (${response.status}): ${errText}`);
    }

    const json = await response.json();
    const content = json.choices?.[0]?.message?.content;

    if (!content) throw new Error("Custom API returned empty content");

    return safeParse(content);
};

export const generateNodeResponse = async (
  targetNodeId: string,
  projectState: ProjectState,
  mode: 'branch' | 'chat' | 'synthesize' | 'refresh' | 'cleanup',
  modelName: string, 
  thinkingBudget: ThinkingBudgetLevel,
  isGroundingEnabled: boolean,
  onProgress?: (stage: ProcessingStage) => void,
  signal?: AbortSignal
): Promise<AIResponse> => {
  const node = projectState.nodes[targetNodeId];
  if (!node) throw new Error("Node not found");

  const checkAbort = () => {
    if (signal?.aborted) throw new Error("Request cancelled by user.");
  };

  checkAbort();

  // --- PREPARE HISTORY ---
  const history: ProjectNode[] = [];
  let curr: ProjectNode | undefined = node;
  while (curr) {
    history.unshift(curr);
    curr = curr.parentId ? projectState.nodes[curr.parentId] : undefined;
  }

  // --- DETERMINE BASELINE STATE ---
  let lastKnownKnowledge = {};
  let lastKnownData: { stores: DataStore[] } = { stores: [] };

  history.forEach((n) => {
    if (n.data?.projectKnowledge && Object.keys(n.data.projectKnowledge).length > 0) {
        lastKnownKnowledge = n.data.projectKnowledge;
    }
    if (n.data?.projectData) {
        lastKnownData = n.data.projectData;
    }
  });

  if (node.data?.projectKnowledge && Object.keys(node.data.projectKnowledge).length > 0) {
      lastKnownKnowledge = node.data.projectKnowledge;
  }
  if (node.data?.projectData) {
      lastKnownData = node.data.projectData;
  }

  // ==========================================
  // PHASE 1: DATA ARCHITECT (WITH RETRY)
  // ==========================================
  onProgress?.('analyzing');
  checkAbort();

  // Clone prompt parts so we can append errors without side-effects on the original construct
  let currentDataPrompt = [...constructDataPrompt(history, node, lastKnownKnowledge, lastKnownData, mode)];
  let dataResult: any;
  let groundingSources: GroundingSource[] = [];

  let attempts = 0;
  const maxAttempts = 3;

  while (attempts < maxAttempts) {
      attempts++;
      try {
          checkAbort();

          if (projectState.modelProvider === 'gemini') {
              const budgetMap: Record<ThinkingBudgetLevel, number> = { low: 512, medium: 4096, high: 32768 };
              const isMapsModel = modelName.includes("2.5");
              const tools: any[] = [];
              if (isGroundingEnabled) {
                  tools.push({ googleSearch: {} });
                  if (isMapsModel) tools.push({ googleMaps: {} });
              }

              const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
              const dataConfig: any = {
                  systemInstruction: getDataSystemInstruction(isGroundingEnabled),
                  tools: tools,
                  thinkingConfig: { thinkingBudget: budgetMap[thinkingBudget] },
                  responseMimeType: "application/json",
                  responseSchema: dataAgentSchema
              };

              const dataResponse = await wrapWithAbort(ai.models.generateContent({
                  model: modelName,
                  contents: { parts: currentDataPrompt },
                  config: dataConfig
              }), signal) as GenerateContentResponse;

              dataResult = safeParse(dataResponse.text || "{}");

              // Validate schema
              validateResponse(dataResult, 'data');

              // Extract Grounding (Only on success)
              const chunks = dataResponse.candidates?.[0]?.groundingMetadata?.groundingChunks;
              if (chunks) {
                  chunks.forEach((chunk: any) => {
                      if (chunk.web?.uri && chunk.web?.title) groundingSources.push({ title: chunk.web.title, uri: chunk.web.uri });
                      if (chunk.maps?.uri && chunk.maps?.title) groundingSources.push({ title: `📍 ${chunk.maps.title}`, uri: chunk.maps.uri });
                  });
              }

              // Break loop on success
              break; 

          } else {
              // CUSTOM PROVIDER
              const { endpoint, modelName: customModel, apiKey } = projectState.customModelConfig;
              if (!endpoint || !customModel) throw new Error("Missing Custom API Configuration");

              dataResult = await callCustomAI(
                  endpoint,
                  customModel,
                  apiKey,
                  getDataSystemInstruction(false),
                  history,
                  currentDataPrompt,
                  dataAgentSchema,
                  signal
              );

              validateResponse(dataResult, 'data');
              break;
          }
      } catch (err: any) {
          if (err.message === "Request cancelled by user.") throw err;
          console.warn(`Data Agent attempt ${attempts} failed:`, err.message);

          if (attempts >= maxAttempts) {
              throw new Error(`Data Agent failed after ${maxAttempts} attempts. Last Error: ${err.message}`);
          }

          // Append error to prompt for next attempt
          currentDataPrompt.push({ 
             text: `\n\nSYSTEM ERROR: The previous response was invalid. Error: "${err.message}". \nPlease fix the JSON structure and ensure all required fields (thoughtProcess, chatReply, updatedData) are present and match the schema.` 
          });
      }
  }

  // ==========================================
  // PHASE 1.5: APPLY DATA UPDATES (IN-MEMORY)
  // ==========================================
  onProgress?.('updating_data');
  checkAbort();

  if (!dataResult.updatedData) dataResult.updatedData = { summary: "No summary", keyPoints: [] };

  if (dataResult.updatedData.projectKnowledgeJson) {
      try { 
          dataResult.updatedData.projectKnowledge = parseOrRaw(dataResult.updatedData.projectKnowledgeJson) || dataResult.updatedData.projectKnowledge;
      } catch(e) {}
  } else {
      dataResult.updatedData.projectKnowledge = lastKnownKnowledge;
  }

  // Execute Store Operations
  let updatedStores = lastKnownData.stores ? [...lastKnownData.stores] : [];
  if (dataResult.updatedData.projectDataUpdates && Array.isArray(dataResult.updatedData.projectDataUpdates)) {
      dataResult.updatedData.projectDataUpdates.forEach((op: any) => {
          const existingIdx = updatedStores.findIndex(s => s.id === op.storeId);

          let schemaMap = parseOrRaw(op.schemaJson) || {};
          let recordsArr = parseOrRaw(op.recordsJson) || [];

          const upsertRecords = (currentRecords: any[], newRecords: any[], schema: any) => {
              const mergedRecords = [...currentRecords];
              const commonKeyFields = ['name', 'title', 'label', 'content', 'task', 'feature', 'ticket', 'item'];
              const schemaKeys = Object.keys(schema || {});
              const businessKey = commonKeyFields.find(k => schemaKeys.includes(k) || (currentRecords.length > 0 && k in currentRecords[0]));

              newRecords.forEach((newRec: any) => {
                  let recordId = newRec.id;

                  if (!recordId && businessKey && newRec[businessKey]) {
                      const candidates = mergedRecords.filter(r => r[businessKey] === newRec[businessKey]);
                      if (candidates.length === 1) {
                          recordId = candidates[0].id;
                      }
                  }

                  if (!recordId) {
                       recordId = `gen-${Math.random().toString(36).substr(2, 9)}`;
                       newRec.id = recordId;
                  } else {
                      newRec.id = recordId;
                  }

                  const matchIdx = mergedRecords.findIndex(r => r.id === recordId);
                  if (matchIdx !== -1) {
                      mergedRecords[matchIdx] = { ...mergedRecords[matchIdx], ...newRec };
                  } else {
                      mergedRecords.push(newRec);
                  }
              });
              return mergedRecords;
          };

          if (op.operation === 'DELETE_STORE') {
              if (existingIdx !== -1) updatedStores.splice(existingIdx, 1);
          } 
          else if (op.operation === 'CREATE_OR_UPDATE_STORE') {
              if (existingIdx !== -1) {
                  const store = updatedStores[existingIdx];
                  const newSchema = (Object.keys(schemaMap).length > 0) ? schemaMap : store.schema;
                  const finalRecords = (recordsArr.length > 0) 
                      ? upsertRecords(store.records, recordsArr, newSchema)
                      : store.records;

                  updatedStores[existingIdx] = {
                      ...store,
                      name: op.name || store.name,
                      schema: newSchema,
                      records: finalRecords
                  };
              } else {
                  updatedStores.push({
                      id: op.storeId,
                      name: op.name || op.storeId,
                      schema: schemaMap,
                      records: recordsArr
                  });
              }
          } 
          else if (op.operation === 'UPSERT_RECORDS') {
              if (existingIdx !== -1) {
                  const store = updatedStores[existingIdx];
                  updatedStores[existingIdx] = { 
                      ...store, 
                      records: upsertRecords(store.records, recordsArr, store.schema) 
                  };
              } else {
                  updatedStores.push({
                      id: op.storeId,
                      name: op.name || op.storeId,
                      schema: schemaMap,
                      records: recordsArr
                  });
              }
          }
          else if (op.operation === 'DELETE_RECORDS') {
              if (existingIdx !== -1) {
                  const store = updatedStores[existingIdx];
                  const idsToDelete = op.recordIds || [];
                  const filteredRecords = store.records.filter(r => !idsToDelete.includes(r.id));
                  updatedStores[existingIdx] = { ...store, records: filteredRecords };
              }
          }
      });
  }

  const nextDataState = {
      stores: updatedStores
  };

  dataResult.updatedData.projectData = nextDataState;

  // ==========================================
  // PHASE 2: UI DESIGNER (WITH RETRY)
  // ==========================================
  onProgress?.('designing_ui');
  checkAbort();

  let currentUIPrompt = [...constructUIPrompt(node.userInput, nextDataState, dataResult.thoughtProcess)];
  let uiResult: any;
  attempts = 0; // Reset attempts for UI Agent

  while (attempts < maxAttempts) {
      attempts++;
      try {
          checkAbort();

          if (projectState.modelProvider === 'gemini') {
              const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
              const uiConfig: any = {
                  systemInstruction: getUISystemInstruction(),
                  thinkingConfig: { thinkingBudget: 1024 }, 
                  responseMimeType: "application/json",
                  responseSchema: uiAgentSchema
              };

              const uiResponse = await wrapWithAbort(ai.models.generateContent({
                  model: modelName, 
                  contents: { parts: currentUIPrompt },
                  config: uiConfig
              }), signal) as GenerateContentResponse;

              uiResult = safeParse(uiResponse.text || "{}");
              validateResponse(uiResult, 'ui');
              break;

          } else {
              // CUSTOM PROVIDER
              const { endpoint, modelName: customModel, apiKey } = projectState.customModelConfig;
              uiResult = await callCustomAI(
                  endpoint,
                  customModel,
                  apiKey,
                  getUISystemInstruction(),
                  [], 
                  currentUIPrompt,
                  uiAgentSchema,
                  signal
              );
              validateResponse(uiResult, 'ui');
              break;
          }
      } catch (err: any) {
          if (err.message === "Request cancelled by user.") throw err;
          console.warn(`UI Agent attempt ${attempts} failed:`, err.message);

          if (attempts >= maxAttempts) {
              // UI Failure fallback
              console.error("UI Agent failed completely. Returning Data Only fallback.");
              uiResult = { 
                  thoughtProcess: "UI Agent failed to generate valid response.",
                  updatedVisualization: { title: "Data Only (Visualization Error)", widgets: [] } 
              };
              break; 
          }

          currentUIPrompt.push({ 
             text: `\n\nSYSTEM ERROR: The previous response was invalid. Error: "${err.message}". \nPlease fix the JSON structure and ensure 'updatedVisualization' matches the schema.` 
          });
      }
  }

  // ==========================================
  // MERGE & SANITIZE
  // ==========================================
  onProgress?.('rendering');
  checkAbort();

  if (!uiResult.updatedVisualization) uiResult.updatedVisualization = { title: "Visualization Error", widgets: [] };

  if (groundingSources.length > 0) {
      const hasRefs = uiResult.updatedVisualization.widgets?.some((w: any) => w.type === WidgetType.REFERENCES);
      if (!hasRefs) {
          if (!uiResult.updatedVisualization.widgets) uiResult.updatedVisualization.widgets = [];
          uiResult.updatedVisualization.widgets.push({
              type: WidgetType.REFERENCES,
              title: "Research & Locations",
              contentItems: groundingSources
          });
      }
  }

  if (uiResult.updatedVisualization.widgets) {
      uiResult.updatedVisualization.widgets = uiResult.updatedVisualization.widgets.map(validateAndSanitizeWidget);
  }

  return {
      updatedData: dataResult.updatedData,
      updatedVisualization: uiResult.updatedVisualization,
      chatReply: dataResult.chatReply || "Processing complete.",
      thoughtProcess: `${dataResult.thoughtProcess}\n\n[UI Designer]: ${uiResult.thoughtProcess || 'Generated widgets based on data.'}`,
      groundingSources: groundingSources.length > 0 ? groundingSources : undefined,
      consolidatedUserIntent: dataResult.consolidatedUserIntent,
      debugInfo: {
          timestamp: Date.now(),
          request: {
              model: projectState.modelProvider === 'gemini' ? modelName : projectState.customModelConfig.modelName,
              prompt: "Multi-step agent chain execution",
              budget: projectState.thinkingBudget === 'low' ? 512 : projectState.thinkingBudget === 'medium' ? 4096 : 32768,
              grounding: isGroundingEnabled
          },
          response: `DATA AGENT:\n${JSON.stringify(dataResult, null, 2)}\n\nUI AGENT:\n${JSON.stringify(uiResult, null, 2)}`
      }
  };
};

import { Type, Schema } from "@google/genai";
import { ProjectNode, WidgetType, DataStore } from "../types";

// --- DATA AGENT (ARCHITECT) ---

export const getDataSystemInstruction = (isGroundingEnabled: boolean) => `
You are the **Data Architect** for "Project Mind". 
Your role is to strictly manage the project's **State** and **Database**.
You do NOT generate UI widgets directly. You generate the DATA that powers them.

CURRENT DATE: ${new Date().toISOString()}

**YOUR RESPONSIBILITIES:**
1. **Analyze Request**: Understand the user's intent within the project history context.
2. **Manage Knowledge**: Update the unstructured 'projectKnowledge' (facts, goals, decisions).
3. **Manage Data**: Execute SQL-like operations in 'projectDataUpdates' to modify the Structured Data Stores.
   - If the user implies a timeline, Create/Update a store with columns for start/end dates.
   - If the user implies metrics, Create/Update a store with number columns.
   - **SDLC Priority**: Ensure data structures support Software Development Life Cycle best practices (e.g., separating Backlog vs. Active, tracking Risks).
   - **DUPLICATE PREVENTION**: 
     - When adding items, check if a similar item already exists in the provided context.
     - When updating or correcting an item, you **MUST** find its 'id' from the context and use it in the record object. 
     - **NEVER** re-create an existing record with a missing ID, as this creates duplicates.
   - **RESPECT DELETIONS (CRITICAL)**:
     - The 'CURRENT DATABASE' provided in the prompt is the **Authoritative Live State**, including user manual deletions.
     - If a record appears in 'CHAT CONVERSATION' history but is missing from 'CURRENT DATABASE', **ASSUME THE USER INTENTIONALLY DELETED IT**.
     - **DO NOT** restore missing/deleted records unless the CURRENT User Input explicitly asks to "restore" or "undelete" them.

${isGroundingEnabled ? `**WEB TOOLS**: You have access to Google Search. Use it to validate technical stacks, look up documentation, or find real-world location data.` : ''}

**OUTPUT FORMAT**:
Return a raw JSON object matching the 'DataAgentSchema'. 
- 'chatReply': A concise response to the user explaining what data changes you made or answering their question.
- 'updatedData': The new state of the project.
`;

export const constructDataPrompt = (
    history: ProjectNode[], 
    node: ProjectNode, 
    lastKnownKnowledge: any, 
    lastKnownData: { stores: DataStore[] },
    mode?: string // Added mode parameter
): any[] => {
  // Build context for the Data Architect
  let promptText = `**PROJECT HISTORY CONTEXT**:\n`;

  history.forEach((n, i) => {
    if (i === history.length - 1) return;
    promptText += `[Step ${i}] User: "${n.userInput}" | Summary: ${n.data?.summary || 'N/A'}\n`;
  });

  promptText += `\n**CURRENT KNOWLEDGE STATE** (Unstructured):\n${JSON.stringify(lastKnownKnowledge, null, 2)}\n`;

  // Schemas Only (Data Architect needs to know structure, but maybe not all 1000 rows)
  const dataSchemas = lastKnownData.stores?.length 
    ? lastKnownData.stores.map(s => {
        const limit = 200;
        const previewRows = s.records.length > limit ? s.records.slice(0, limit) : s.records; 
        const truncatedMsg = s.records.length > limit ? `\n...(Truncated: Showing first ${limit} of ${s.records.length} records. If you need to update a record not listed here, try to infer it or ask for a specific search)` : '';
        return `- Store "${s.id}" (${s.name}):\n  Schema: ${JSON.stringify(s.schema)}\n  Content: ${JSON.stringify(previewRows)}${truncatedMsg}`;
      }).join('\n\n')
    : "No structured data stores defined.";

  promptText += `\n**CURRENT DATABASE (Live State)**:\n${dataSchemas}\n(Note: Records missing here but present in history have been deleted. Do not restore them.)\n`;

  promptText += `\n**ACTIVE REQUEST**:\nUser Input: "${node.userInput}"\n`;

  if (mode === 'cleanup') {
      promptText += `\n**TASK: CLEANUP & CONSOLIDATE**\nThe user wants to compress this entire history into a single clean state.

      ${node.userInput ? `**USER FOCUS INSTRUCTION**: "${node.userInput}"\n(Prioritize this aspect in the summary and data retention. Discard irrelevant details if asked.)\n` : ''}

1. Review the entire context.
2. In 'consolidatedUserIntent', write a SINGLE clear user prompt that would have led to this current state. 
   - **FORMAT**: Use Markdown (bullet points, bold text) to make this prompt structured and readable. 
   - It should act as a "Master Prompt" that could regenerate this state.
3. Ensure 'chatReply' is a comprehensive executive summary of the entire project status.
   - **FORMAT**: Use Markdown.
4. Ensure 'updatedData' reflects the most current, accurate state of all data.`;
  } else {
      promptText += `\n**INSTRUCTION**: Analyze the request. If new data is provided, generate 'projectDataUpdates' to UPSERT it into the stores. Update 'projectKnowledge' with any new facts. Remember to use existing IDs for updates to avoid duplicates. Respect manual deletions in the DB.`;
  }

  const parts: any[] = [{ text: promptText }];

  // Attachments
  if (node.userAttachments) {
    node.userAttachments.forEach(att => {
        if (att.type.startsWith('image/')) {
            parts.push({ inlineData: { mimeType: att.type, data: att.data.split(',')[1] } });
        } else {
            parts.push({ text: `[Attachment: ${att.name}]` });
        }
    });
  }

  // Chat History
  if (node.chat && node.chat.length > 0) {
      parts.push({ text: `\n**CHAT CONVERSATION**:\n` });
      node.chat.forEach(c => {
          parts.push({ text: `${c.role.toUpperCase()}: ${c.text}` });
          if (c.attachments) {
            c.attachments.forEach(att => {
                 if (att.type.startsWith('image/')) {
                    parts.push({ inlineData: { mimeType: att.type, data: att.data.split(',')[1] } });
                 }
            });
          }
      });
  }

  return parts;
};

export const dataAgentSchema: Schema = {
    type: Type.OBJECT,
    properties: {
        thoughtProcess: { type: Type.STRING, description: "Reasoning about data needs." },
        chatReply: { type: Type.STRING, description: "Conversational response to the user." },
        consolidatedUserIntent: { type: Type.STRING, description: "For 'cleanup' mode: A single summary prompt representing the user's cumulative intent." },
        updatedData: {
            type: Type.OBJECT,
            properties: {
                summary: { type: Type.STRING },
                keyPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
                projectKnowledgeJson: { type: Type.STRING, description: "Stringified JSON of unstructured knowledge." },
                projectDataUpdates: {
                    type: Type.ARRAY,
                    description: "Array of DB operations.",
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            operation: { type: Type.STRING, enum: ['CREATE_OR_UPDATE_STORE', 'UPSERT_RECORDS', 'DELETE_STORE', 'DELETE_RECORDS'] },
                            storeId: { type: Type.STRING },
                            name: { type: Type.STRING },
                            schemaJson: { type: Type.STRING, description: "JSON string of schema (key: type)" },
                            recordsJson: { type: Type.STRING, description: "JSON string of array of records. IMPORTANT: Each record MUST have a unique 'id' field." },
                            recordIds: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ['operation', 'storeId']
                    }
                }
            },
            required: ["summary", "keyPoints"]
        }
    },
    required: ["thoughtProcess", "chatReply", "updatedData"]
};


// --- UI AGENT (DESIGNER) ---

export const getUISystemInstruction = () => `
You are the **UI Designer** for "Project Mind".
Your goal is to visualize the provided **DATA** using the Bento Widget System.
You do NOT manage data. You only Render it.

**AVAILABLE WIDGETS**:
- **GANTT**: For timelines (needs start/end dates).
- **KANBAN**: For workflows/status (needs groupable field).
- **METRICS**: For key numbers (KPIs, health scores).
- **RISK_MATRIX**: For Impact vs Likelihood (1-5).
- **CHART**: Bar/Line/Area for numerical trends.
- **MAP**: For locations.
- **TABLE**: For raw data views.
- **CODE**: For scripts.

**CRITICAL INSTRUCTION**:
- Look at the **DATA STORES** provided in the context.
- Choose widgets that best represent this data.
- **BINDING**: Use the 'dataSource' property to bind a widget to a 'storeId'. Use 'fieldMapping' to tell the renderer which DB columns map to the widget's expected keys.
- **MANDATORY**: You **MUST** use 'dataSource' for GANTT, KANBAN, TABLE, and CHART widgets. 
- **FORBIDDEN**: Do NOT hardcode data into 'tasks', 'columns', 'rows', or 'data' arrays for these widgets. If you hardcode it, the widget will not update when the database changes. 
- You can leave the hardcoded data arrays empty if 'dataSource' is provided. The app will hydrate them.
- If the user asks for a specific view (e.g., "Show me a roadmap"), prioritize that widget.

**OUTPUT FORMAT**:
Return a raw JSON object matching the 'UIAgentSchema'.
`;

export const constructUIPrompt = (
    userRequest: string,
    updatedData: { stores: DataStore[] },
    dataAgentThought: string
): any[] => {
    let promptText = `**CONTEXT FROM DATA ARCHITECT**:\n`;
    promptText += `Thought Process: "${dataAgentThought}"\n`;
    promptText += `User Request: "${userRequest}"\n`;

    promptText += `\n**AVAILABLE DATA STORES (The Source of Truth)**:\n`;

    if (updatedData.stores.length === 0) {
        promptText += "No structured data available. (You may generate a message widget or empty state).\n";
    } else {
        updatedData.stores.forEach(s => {
            const preview = s.records.slice(0, 50); 
            promptText += `\n[Store ID: "${s.id}"] Name: "${s.name}"\nSchema: ${JSON.stringify(s.schema)}\nRows Preview:\n${JSON.stringify(preview, null, 2)}\n`;
        });
    }

    promptText += `\n**INSTRUCTION**: Generate a 'updatedVisualization' object. Select the best widgets to display this data. \n**IMPORTANT**: Map store columns to widget fields using 'dataSource'. Do not hardcode data arrays.\n`;

    return [{ text: promptText }];
};

export const uiAgentSchema: Schema = {
    type: Type.OBJECT,
    properties: {
        thoughtProcess: { type: Type.STRING, description: "Why I chose these widgets." },
        updatedVisualization: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                widgets: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            type: { type: Type.STRING, enum: Object.values(WidgetType) },
                            title: { type: Type.STRING },
                            dataSource: {
                                type: Type.OBJECT,
                                properties: {
